mapper.select:

SELECT *
FROM 
	EXAM_POLICY_DETAIL
WHERE
	ENABLED_FLAG=1


AND ID=#{id}


AND EXAM_POLICY_ID=#{examPolicyId}


AND upper(TYPE) like upper('%${type}%')


AND upper(LEV) like upper('%${lev}%')


AND QUESTION_COUNT=#{questionCount}


AND PER_SCORE=#{perScore}


AND LAST_UPDATE_DATE=#{lastUpdateDate}


AND LAST_UPDATED_BY=#{lastUpdatedBy}


AND CREATION_DATE=#{creationDate}


AND CREATED_BY=#{createdBy}


AND ENABLED_FLAG=#{enabledFlag}

ORDER BY ID


SELECT 
	*
FROM 
	EXAM_POLICY_DETAIL
WHERE
	ENABLED_FLAG=1


AND ID=#{bo.id}


AND EXAM_POLICY_ID=#{bo.examPolicyId}


AND upper(TYPE) like upper('%${bo.type}%')


AND upper(LEV) like upper('%${bo.lev}%')


AND QUESTION_COUNT=#{bo.questionCount}


AND PER_SCORE=#{bo.perScore}


AND LAST_UPDATE_DATE=#{bo.lastUpdateDate}


AND LAST_UPDATED_BY=#{bo.lastUpdatedBy}


AND CREATION_DATE=#{bo.creationDate}


AND CREATED_BY=#{bo.createdBy}


AND ENABLED_FLAG=#{bo.enabledFlag}

ORDER BY ${page.sortFieldName} DESC

SELECT EXAM_POLICY_ID as EPID, SUM(QUESTION_COUNT) as QNUM FROM EXAM_POLICY_DETAIL WHERE ENABLED_FLAG=1 and EXAM_POLICY_ID IN
#{id}
GROUP BY EXAM_POLICY_ID
